const fs = require('fs');
const css = fs.readFileSync('src/app.css', 'utf8');
const checks = [
  ['body background', /background\s*:\s*#1e1e1e/],
  ['body color', /color\s*:\s*#e6e6e6/],
  ['body font-size 14px', /font-size\s*:\s*14px/],
  ['system font stack', /-apple-system/],
  ['.trigger background #3a3d41', /\.trigger[^}]*background\s*:\s*#3a3d41/],
  ['.trigger:hover #45494d', /\.trigger:hover[^}]*background\s*:\s*#45494d/],
  ['.browser-dialog background #252526', /\.browser-dialog[^}]*background\s*:\s*#252526/],
  ['.browser-dialog border-radius 8px', /\.browser-dialog[^}]*border-radius\s*:\s*8px/],
  ['.browser-dialog max-width 960px', /\.browser-dialog[^}]*max-width\s*:\s*960px/],
  ['::backdrop rgba(0,0,0,0.6)', /::backdrop[^}]*background\s*:\s*rgba\(0\s*,\s*0\s*,\s*0\s*,\s*0\.6\)/],
  ['header flex space-between', /justify-content\s*:\s*space-between/],
  ['.toolbar flex wrap gap', /\.toolbar[^}]*flex-wrap\s*:\s*wrap/],
  ['search input #333337', /background\s*:\s*#333337/],
  ['table width 100%', /\.results-table[^}]*width\s*:\s*100%/],
  ['th/td padding 6px 8px', /padding\s*:\s*6px\s+8px/],
  ['tr:hover #2d2d30', /tr:hover[^}]*background\s*:\s*#2d2d30/],
  ['th muted #9a9a9a', /\.results-table th[^}]*color\s*:\s*#9a9a9a/],
  ['.folder-row font-weight 600', /\.folder-row[^}]*font-weight\s*:\s*600/],
  ['.btn styling', /\.btn[^}]*background\s*:\s*#3a3d41/],
  ['.status muted', /\.status[^}]*color\s*:\s*#9a9a9a/],
  ['.results-container max-height overflow', /\.results-container[^}]*overflow\s*:\s*auto/],
  ['accent link #6aa6ff', /color\s*:\s*#6aa6ff/],
  ['borders #3c3c3c', /border[^}]*#3c3c3c/g],
  ['panels #252526', /background\s*:\s*#252526/g],
];
let allPass = true;
for (const [name, regex] of checks) {
  const ok = regex.test(css);
  console.log((ok ? 'PASS' : 'FAIL') + ': ' + name);
  if (!ok) allPass = false;
}
console.log(allPass ? '\\nAll checks passed!' : '\\nSome checks failed!');
process.exit(allPass ? 0 : 1);
"
